class Solution:
    def filterRestaurants(self, restaurants, veganFriendly, maxPrice, maxDistance):
        filtered = []
        for r in restaurants:
            rid, rating, vegan, price, dist = r
            if veganFriendly == 1 and vegan == 0:
                continue
            if price > maxPrice or dist > maxDistance:
                continue
            filtered.append((rating, rid))
        filtered.sort(key=lambda x: (x[0], x[1]), reverse=True)
        return [rid for _, rid in filtered]

